import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { getMyFeedback } from '../../services/dataService';
import { formatDate } from '../../utils/helpers';
import StatusBadge from '../../components/common/StatusBadge';
import LoadingSpinner from '../../components/common/LoadingSpinner';
import { FiPlus, FiStar } from 'react-icons/fi';

const CustomerFeedback = () => {
  const [feedbacks, setFeedbacks] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetch = async () => {
      try {
        const res = await getMyFeedback();
        setFeedbacks(res.data.data);
      } catch (err) { console.error(err); }
      finally { setLoading(false); }
    };
    fetch();
  }, []);

  if (loading) return <LoadingSpinner />;

  return (
    <div>
      <div className="page-header">
        <h1>My Feedback</h1>
        <Link to="/customer/feedback/new" className="btn btn-primary"><FiPlus /> Submit Feedback</Link>
      </div>

      {feedbacks.length === 0 ? (
        <div className="empty-state"><p>No feedback submitted yet</p></div>
      ) : (
        <div>
          {feedbacks.map(f => (
            <div key={f._id} className="card" style={{ marginBottom: '16px' }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                <div>
                  <h3>{f.title}</h3>
                  <div style={{ display: 'flex', gap: '8px', marginBottom: '8px' }}>
                    <StatusBadge status={f.category} />
                    <StatusBadge status={f.status} />
                    <span style={{ display: 'flex', alignItems: 'center', gap: '2px' }}>
                      {[...Array(5)].map((_, i) => (
                        <FiStar key={i} fill={i < f.rating ? '#ffd166' : 'none'} color="#ffd166" size={14} />
                      ))}
                    </span>
                  </div>
                  <p>{f.message}</p>
                </div>
                <small>{formatDate(f.createdAt)}</small>
              </div>
              {f.adminResponse && (
                <div style={{ marginTop: '12px', padding: '12px', background: '#f8f9fa', borderRadius: '8px' }}>
                  <strong>Admin Response:</strong>
                  <p>{f.adminResponse}</p>
                </div>
              )}
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default CustomerFeedback;
